// Download component for file download functionality
import React, { useState } from 'react';

const Download = ({ files, onFileChange }) => {
    const [downloading, setDownloading] = useState(null);
    const [message, setMessage] = useState('');

    const handleDownload = async (fileId, fileName) => {
        setDownloading(fileId);
        setMessage('');

        try {
            const response = await fetch(`/api/files/download/${fileId}`);
            
            if (response.ok) {
                const blob = await response.blob();
                const url = window.URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = fileName;
                document.body.appendChild(a);
                a.click();
                window.URL.revokeObjectURL(url);
                document.body.removeChild(a);
                
                setMessage(`Downloaded ${fileName} successfully`);
            } else {
                const errorData = await response.json();
                setMessage('Download failed: ' + errorData.error);
            }
        } catch (error) {
            setMessage('Download failed: ' + error.message);
        } finally {
            setDownloading(null);
        }
    };

    const handleDelete = async (fileId) => {
        if (!window.confirm('Are you sure you want to delete this file?')) {
            return;
        }

        try {
            const response = await fetch(`/api/files/${fileId}`, {
                method: 'DELETE'
            });

            if (response.ok) {
                setMessage('File deleted successfully');
                onFileChange();
            } else {
                const errorData = await response.json();
                setMessage('Delete failed: ' + errorData.error);
            }
        } catch (error) {
            setMessage('Delete failed: ' + error.message);
        }
    };

    const formatFileSize = (bytes) => {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const sizes = ['Bytes', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    };

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleString();
    };

    return (
        <div className="download-container">
            <h2>Available Files</h2>
            
            {!Array.isArray(files) || files.length === 0 ? (
                <p>No files available for download.</p>
            ) : (
                <div className="file-list">
                    {files.map((file) => (
                        <div key={file._id} className="file-item">
                            <div className="file-details">
                                <h4>{file.originalName}</h4>
                                <p>Size: {formatFileSize(file.size)}</p>
                                <p>Uploaded: {formatDate(file.uploadedAt)}</p>
                            </div>
                            <div className="file-actions">
                                <button 
                                    onClick={() => handleDownload(file._id, file.originalName)}
                                    disabled={downloading === file._id}
                                    className="download-btn"
                                >
                                    {downloading === file._id ? 'Downloading...' : 'Download'}
                                </button>
                                <button 
                                    onClick={() => handleDelete(file._id)}
                                    className="delete-btn"
                                >
                                    Delete
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {message && (
                <div className={`message ${message.includes('success') ? 'success' : 'error'}`}>
                    {message}
                </div>
            )}
        </div>
    );
};

export default Download;
